import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Chapter 11: Code Intelligence","description":"Building semantic code understanding with tree-sitter parsing, AST queries, grep at scale, and language server protocol fundamentals.","frontmatter":{"title":"Chapter 11: Code Intelligence","description":"Building semantic code understanding with tree-sitter parsing, AST queries, grep at scale, and language server protocol fundamentals."},"headers":[],"relativePath":"learn/linear/11-code-intelligence/index.md","filePath":"learn/linear/11-code-intelligence/index.md"}'),n={name:"learn/linear/11-code-intelligence/index.md"};function l(o,e,s,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="code-intelligence" tabindex="-1">Code Intelligence <a class="header-anchor" href="#code-intelligence" aria-label="Permalink to &quot;Code Intelligence&quot;">​</a></h1><p>This chapter moves beyond treating source code as plain text. A coding agent that can only do string matching is fundamentally limited — it cannot distinguish a function definition from a function call, a variable declaration from a reference, or a comment from executable code. Tree-sitter provides the foundation for semantic code understanding by parsing source files into concrete syntax trees that capture the full grammatical structure of the code.</p><p>You will learn tree-sitter from the ground up: how its incremental parsing algorithm works, how grammar definitions map source text to typed tree nodes, and how the S-expression query language lets you extract specific patterns like &quot;all function definitions that take more than three parameters.&quot; These capabilities transform what an agent can do — instead of grepping for text patterns, it can navigate code by structure, understand scope and nesting, and make changes that respect the syntax of the language.</p><p>The chapter also covers the practical tools that complement tree-sitter in a code intelligence stack: high-performance grep with ripgrep for text-level search, glob patterns for file discovery, and the Language Server Protocol (LSP) that provides IDE-level features like go-to-definition, find-references, and diagnostics. Together, these tools give the agent a rich understanding of the codebase it operates on.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand why structural code understanding outperforms text search for agent tasks</li><li>Parse source code with tree-sitter and navigate the resulting concrete syntax tree</li><li>Write tree-sitter queries to extract functions, classes, imports, and other structural patterns</li><li>Implement high-performance code search using ripgrep with glob filtering and regex patterns</li><li>Understand the Language Server Protocol architecture and how it provides semantic code features</li><li>Combine text search, structural queries, and LSP features for comprehensive code navigation</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/11-code-intelligence/01-beyond-text-search.html">Beyond Text Search</a></li><li><a href="/linear/11-code-intelligence/02-tree-sitter-fundamentals.html">Tree Sitter Fundamentals</a></li><li><a href="/linear/11-code-intelligence/03-parsing-source-code.html">Parsing Source Code</a></li><li><a href="/linear/11-code-intelligence/04-ast-queries.html">AST Queries</a></li><li><a href="/linear/11-code-intelligence/05-semantic-understanding.html">Semantic Understanding</a></li><li><a href="/linear/11-code-intelligence/06-language-grammars.html">Language Grammars</a></li><li><a href="/linear/11-code-intelligence/07-grep-at-scale.html">Grep at Scale</a></li><li><a href="/linear/11-code-intelligence/08-glob-patterns.html">Glob Patterns</a></li><li><a href="/linear/11-code-intelligence/09-code-navigation.html">Code Navigation</a></li><li><a href="/linear/11-code-intelligence/10-symbol-resolution.html">Symbol Resolution</a></li><li><a href="/linear/11-code-intelligence/11-language-server-protocol-basics.html">Language Server Protocol Basics</a></li><li><a href="/linear/11-code-intelligence/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 6 (file system operations for reading and discovering source files in a codebase)</li><li>Basic familiarity with syntax trees and parsing concepts (helpful but not required)</li></ul>',10)])])}const p=t(n,[["render",l]]);export{u as __pageData,p as default};
